const input = $input.first().json;
const body = input.body ?? input;
const expectedToken = String($env.YOUTUBE_PUBLISH_APPROVAL_TOKEN || '').trim();
const providedToken = String(body.approvalToken || body.publishApprovalToken || '').trim();
const publishApproved = Boolean(expectedToken && providedToken && providedToken === expectedToken && body.confirm === 'publish-to-youtube');
const uploadEnabled = true;

function text(value) {
  return typeof value === 'string' ? value.trim() : '';
}

function firstText(...values) {
  for (const value of values) {
    const result = text(value);
    if (result) return result;
  }
  return '';
}

function clamp(value, max) {
  const result = text(value);
  return result.length > max ? result.slice(0, max).trim() : result;
}

function arrayFrom(value) {
  if (Array.isArray(value)) return value;
  return String(value || '').split(',');
}

function isPlainObject(value) {
  return Boolean(value && typeof value === 'object' && !Array.isArray(value));
}

function arrayOfObjects(...values) {
  for (const value of values) {
    if (Array.isArray(value)) return value.filter(isPlainObject);
  }
  return [];
}

function explicitBoolean(...values) {
  for (const value of values) {
    if (typeof value === 'boolean') return value;
    if (value === 'true') return true;
    if (value === 'false') return false;
  }
  return undefined;
}

function isHttpUrl(value) {
  return /^https?:\/\//i.test(String(value || '').trim());
}

function assetUrl(asset) {
  return firstText(asset.downloadUrl, asset.publicUrl, asset.url, asset.storage?.downloadUrl, asset.href);
}

function assetRole(asset) {
  return text(asset.role).toLowerCase();
}

function assetMediaType(asset) {
  return text(asset.mediaType || asset.type).toLowerCase();
}

function pickAssetUrl(assets, roleMatchers, mediaTypes) {
  const byRole = assets.find((asset) => roleMatchers.some((matcher) => matcher.test(assetRole(asset))) && assetUrl(asset));
  if (byRole) return assetUrl(byRole);
  const byType = assets.find((asset) => mediaTypes.includes(assetMediaType(asset)) && assetUrl(asset));
  return byType ? assetUrl(byType) : '';
}

const BLOCKED_PUBLIC_TERMS = [
  'OpenClaw',
  'media-worker',
  'media worker',
  'internal project',
  'internal tool',
  'n8n',
  'ComfyUI',
  'RabbitMQ',
  'karaoke'
];

function blockedPublicTerm(value) {
  const textValue = (Array.isArray(value) ? value.join(', ') : String(value || '')).toLowerCase();
  return BLOCKED_PUBLIC_TERMS.find((term) => textValue.includes(String(term).toLowerCase()));
}

const artifacts = isPlainObject(body.artifacts) ? body.artifacts : {};
const metadata = isPlainObject(body.metadata) ? body.metadata : {};
const youtubeMetadata = isPlainObject(metadata.youtube) ? metadata.youtube : {};
const publishingMetadata = isPlainObject(metadata.publishing) ? metadata.publishing : {};
const musicMetadata = isPlainObject(metadata.musicRequest) ? metadata.musicRequest : {};
const assets = arrayOfObjects(body.assets, artifacts.assets, body.assetMetadata, artifacts.assetMetadata);
const finalVideoFromAssets = pickAssetUrl(assets, [/^primary_video$/, /final.*video/, /video/], ['video']);
const thumbnailFromAssets = pickAssetUrl(assets, [/^cover$/, /^thumbnail$/, /thumb/, /poster/], ['image']);
const requestId = firstText(body.requestId, metadata.requestId);
const artifactPageUrl = firstText(body.artifactPageUrl, artifacts.pageUrl, artifacts.artifactPageUrl);
const finalVideoUrl = firstText(body.finalVideoUrl, artifacts.finalVideoUrl, artifacts.mp4Url, artifacts.videoUrl, finalVideoFromAssets);
const thumbnailUrl = firstText(body.thumbnailUrl, artifacts.thumbnailUrl, thumbnailFromAssets);
const finalVideoRole = assets.find((asset) => assetUrl(asset) === finalVideoUrl)?.role || null;
const thumbnailRole = assets.find((asset) => assetUrl(asset) === thumbnailUrl)?.role || null;
const title = clamp(firstText(body.title, youtubeMetadata.title, publishingMetadata.title, metadata.title), 100);
const descriptionBase = firstText(body.description, youtubeMetadata.description, publishingMetadata.description, metadata.description);
const description = clamp(descriptionBase, 5000);
const metadataTags = Array.isArray(youtubeMetadata.tags) ? youtubeMetadata.tags : (Array.isArray(publishingMetadata.tags) ? publishingMetadata.tags : arrayFrom(youtubeMetadata.tags || publishingMetadata.tags || metadata.tags));
const tags = Array.isArray(body.tags) ? body.tags : metadataTags;
const cleanTags = [...new Set(tags.map((tag) => text(tag)).filter(Boolean))].slice(0, 25);
const privacyStatus = ['private', 'unlisted', 'public'].includes(body.privacyStatus) ? body.privacyStatus : (['private', 'unlisted', 'public'].includes(youtubeMetadata.privacyStatus) ? youtubeMetadata.privacyStatus : 'private');
const categoryId = String(body.categoryId || youtubeMetadata.categoryId || '10');
const regionCode = String(body.regionCode || youtubeMetadata.regionCode || 'VN');
const madeForKids = explicitBoolean(body.madeForKids, youtubeMetadata.madeForKids);
const language = firstText(body.language, body.defaultLanguage, youtubeMetadata.language, youtubeMetadata.defaultLanguage, musicMetadata.language);
const duplicateKey = firstText(body.duplicateKey, publishingMetadata.duplicateKey, requestId);

let duplicateRecord = null;
let ledgerAvailable = false;
try {
  const workflowStatic = typeof $getWorkflowStaticData === 'function' ? $getWorkflowStaticData('global') : null;
  const ledger = workflowStatic && workflowStatic.youtubePublishLedger && typeof workflowStatic.youtubePublishLedger === 'object'
    ? workflowStatic.youtubePublishLedger
    : {};
  ledgerAvailable = Boolean(workflowStatic);
  duplicateRecord = duplicateKey && ledger[duplicateKey] ? ledger[duplicateKey] : null;
  const knownPublishedVideos = {
    'happy-birthday-lucy-music-video-20260619120120-ltxv-sheet': {
      requestId: 'happy-birthday-lucy-music-video-20260619120120-ltxv-sheet',
      videoId: 'FHJKJSsnkHw',
      privacyStatus: 'private',
      source: 'first-controlled-private-upload',
      uploadedAt: '2026-06-26T05:15:45Z',
      ledgerRecorded: false,
      note: 'Upload succeeded; thumbnail failed with YouTube custom thumbnail permission 403 before ledger node.'
    }
  };
  if (!duplicateRecord && duplicateKey && knownPublishedVideos[duplicateKey]) {
    duplicateRecord = knownPublishedVideos[duplicateKey];
  }
} catch (error) {
  ledgerAvailable = false;
}

const missing = [];
if (!requestId) missing.push('requestId');
if (!artifactPageUrl) missing.push('artifactPageUrl');
if (!finalVideoUrl) missing.push('finalVideoUrl');
if (!thumbnailUrl) missing.push('thumbnailUrl');
if (!title) missing.push('metadata.youtube.title');
if (!descriptionBase) missing.push('metadata.youtube.description');
if (!cleanTags.length) missing.push('metadata.youtube.tags');
if (!duplicateKey) missing.push('metadata.publishing.duplicateKey');
if (!language) missing.push('metadata.youtube.language');
if (madeForKids === undefined) missing.push('metadata.youtube.madeForKids');

const validationErrors = [];
if (artifactPageUrl && !isHttpUrl(artifactPageUrl)) validationErrors.push('artifactPageUrl must be http(s)');
if (finalVideoUrl && !isHttpUrl(finalVideoUrl)) validationErrors.push('finalVideoUrl must be http(s)');
if (thumbnailUrl && !isHttpUrl(thumbnailUrl)) validationErrors.push('thumbnailUrl must be http(s)');
if (!['private', 'unlisted', 'public'].includes(privacyStatus)) validationErrors.push('metadata.youtube.privacyStatus must be private, unlisted, or public');
if (privacyStatus !== 'private') validationErrors.push('private publish requires privacyStatus=private');
const titleBlockedTerm = blockedPublicTerm(title);
const descriptionBlockedTerm = blockedPublicTerm(description);
const tagsBlockedTerm = blockedPublicTerm(cleanTags);
if (titleBlockedTerm) validationErrors.push(`metadata.youtube.title contains blocked public term: ${titleBlockedTerm}`);
if (descriptionBlockedTerm) validationErrors.push(`metadata.youtube.description contains blocked public term: ${descriptionBlockedTerm}`);
if (tagsBlockedTerm) validationErrors.push(`metadata.youtube.tags contains blocked public term: ${tagsBlockedTerm}`);

const gateBlocks = [];
if (missing.length) gateBlocks.push(`missing:${missing.join(',')}`);
if (validationErrors.length) gateBlocks.push(`invalid:${validationErrors.join(',')}`);
if (!publishApproved) gateBlocks.push('approval_required');
if (duplicateRecord) gateBlocks.push('duplicate_publish_key');
if (!uploadEnabled) gateBlocks.push('upload_branch_disabled');

const ok = missing.length === 0 && validationErrors.length === 0;
const readyForUpload = ok && publishApproved && !duplicateRecord && uploadEnabled;
const responseCode = ok ? (duplicateRecord ? 409 : 200) : 400;
const status = !ok ? 'invalid_package' : duplicateRecord ? 'duplicate_blocked' : readyForUpload ? 'approved_private_publish_ready' : 'private_publish_preflight';

return [{ json: {
  ok,
  responseCode,
  status,
  route: readyForUpload ? 'publish' : 'blocked',
  requestId,
  publishApproved,
  uploadEnabled,
  readyForUpload,
  duplicate: Boolean(duplicateRecord),
  duplicateRecord,
  ledgerAvailable,
  gateBlocks,
  message: ok
    ? (duplicateRecord
      ? `Duplicate publish blocked for key: ${duplicateKey}`
      : (readyForUpload ? 'Package passed validation and explicit approval. Upload branch is enabled for this one-time request.' : (publishApproved ? 'Package passed validation and explicit approval. Upload remains disabled until the final publish switch is enabled.' : 'Package passed validation. Private upload requires confirm=publish-to-youtube and approvalToken.')))
    : `Package validation failed: ${[...missing, ...validationErrors].join(', ')}`,
  missing,
  validationErrors,
  uploadPlan: {
    requestId,
    duplicateKey,
    finalVideoUrl,
    thumbnailUrl,
    artifactPageUrl,
    finalVideoRole,
    thumbnailRole,
    artifactCount: assets.length,
    artifactRoles: assets.map((asset) => asset.role).filter(Boolean),
    title,
    description,
    tags: cleanTags,
    tagsCsv: cleanTags.join(','),
    privacyStatus,
    categoryId,
    regionCode,
    language,
    madeForKids,
    notifySubscribers: false
  },
  thumbnailPlan: {
    sourceUrl: thumbnailUrl,
    role: thumbnailRole,
    requiresVideoId: true,
    endpoint: 'https://www.googleapis.com/upload/youtube/v3/thumbnails/set',
    stagedNode: 'Set YouTube Thumbnail'
  },
  rollbackPlan: {
    deleteUploadedVideo: 'Use YouTube video delete by videoId if an accidental upload occurs.',
    clearLedgerKey: duplicateKey ? `Remove youtubePublishLedger[${duplicateKey}] from workflow static data only after confirming YouTube rollback.` : '',
    keepSourceArtifact: artifactPageUrl
  }
} }];

const item = $input.first().json;
const uploadPlan = $('Validate Private Publish Gate').first().json.uploadPlan || {};
const upload = $('Upload Private Video to YouTube').first().json || {};
const key = String(uploadPlan.duplicateKey || uploadPlan.requestId || '').trim();
if (!key) {
  throw new Error('Cannot record YouTube publish ledger without duplicateKey');
}
const videoId = upload.id || upload.videoId || upload.uploadId || upload.uploadResult?.id || null;
const workflowStatic = $getWorkflowStaticData('global');
workflowStatic.youtubePublishLedger = workflowStatic.youtubePublishLedger || {};
workflowStatic.youtubePublishLedger[key] = {
  requestId: uploadPlan.requestId || key,
  videoId,
  title: uploadPlan.title || null,
  privacyStatus: 'private',
  artifactPageUrl: uploadPlan.artifactPageUrl || null,
  recordedAt: new Date().toISOString(),
  thumbnailStatus: 'pending'
};
return [{ json: { ...item, uploadPlan, youtubeUpload: upload, videoId, uploadId: videoId, ledgerRecorded: true, ledgerKey: key, thumbnailStatus: 'pending' } }];
